import { ExternalLink, Github } from 'lucide-react';
// import project1Image from '@/assets/project-1.jpg';
// import project2Image from '@/assets/project-2.jpg';
// import project3Image from '@/assets/project-3.jpg';

const Projects = () => {
  const projects = [
    {
      id: 1,
      title: "Task Management Dashboard",
      description: "A comprehensive project management tool built with React and Node.js. Features real-time collaboration, task tracking, and team analytics.",
    //   image: project1Image,
      technologies: ["React", "Node.js", "MongoDB", "Socket.io"],
      githubUrl: "https://github.com",
      liveUrl: "https://example.com"
    },
    {
      id: 2,
      title: "College Event Management System",
      description: "Modern e-commerce application with seamless user experience, payment integration, and inventory management system.",
    //   image: project2Image,
      technologies: ["React Native", "Express.js", "PostgreSQL", "Stripe"],
      githubUrl: "https://github.com/RamanjotKaur7856/College-Event-Management-System",
      liveUrl: "https://example.com"
    },
    {
      id: 3,
      title: "Blog Management System",
      description: "Interactive data visualization platform for business intelligence with real-time charts and customizable dashboards.",
    //   image: project3Image,
      technologies: ["Vue.js", "Python", "Django", "Chart.js"],
      githubUrl: "https://github.com/RamanjotKaur7856/Blog-Management-System",
      liveUrl: "https://example.com"
    }
  ];

  return (
    <section id="projects" className="projects">
      <div className="container">
        <h2 className="section-title">Projects</h2>

        <div className="projects-grid lg-grid-cols-3">
          {projects.map((project) => (
            <div key={project.id} className="project-card">
              <div className="project-image-container">
                <img
                  src={project.image}
                  alt={project.title}
                  className="project-image"
                />
                <div className="project-overlay">
                  <div className="project-overlay-content">
                    <a
                      href={project.githubUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="project-overlay-link"
                    >
                      <Github size={20} />
                    </a>
                    <a
                      href={project.liveUrl}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="project-overlay-link"
                    >
                      <ExternalLink size={20} />
                    </a>
                  </div>
                </div>
              </div>

              <div>
                <h3 className="project-title">{project.title}</h3>
                <p className="project-description">{project.description}</p>

                <div className="project-technologies">
                  {project.technologies.map((tech) => (
                    <span key={tech} className="project-tech-tag">{tech}</span>
                  ))}
                </div>

                <div className="project-actions">
                  <a href={project.githubUrl} target="_blank" rel="noopener noreferrer" className="project-action-link btn btn-outline">
                    Code
                  </a>
                  <a href={project.liveUrl} target="_blank" rel="noopener noreferrer" className="project-action-link btn btn-primary">
                    Live Demo
                  </a>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="text-center" style={{ marginTop: 'var(--spacing-12)' }}>
          <a href="https://github.com/RamanjotKaur7856" target="_blank" rel="noopener noreferrer" className="btn btn-outline">
            View All Projects
            <Github size={20} />
          </a>
        </div>
      </div>
    </section>
  );
};

export default Projects;
